/* ─── SIGNATURE PAD ─────────────────────────────────────────── */
function SigPad({onSave,onClear,label}){
  const ref=useRef(); const drawing=useRef(false); const last=useRef({x:0,y:0});
  const ctx=()=>ref.current?.getContext("2d");
  const pos=(e,el)=>{ const r=el.getBoundingClientRect(); const src=e.touches?e.touches[0]:e; return{x:src.clientX-r.left,y:src.clientY-r.top}; };
  const start=e=>{ drawing.current=true; const p=pos(e,ref.current); last.current=p; ctx().beginPath(); ctx().moveTo(p.x,p.y); e.preventDefault(); };
  const move=e=>{ if(!drawing.current)return; const p=pos(e,ref.current); const c=ctx(); c.lineWidth=2; c.lineCap="round"; c.strokeStyle="#3b82f6"; c.lineTo(p.x,p.y); c.stroke(); c.beginPath(); c.moveTo(p.x,p.y); last.current=p; e.preventDefault(); };
  const end=()=>{ drawing.current=false; };
  const clear=()=>{ const c=ref.current; ctx().clearRect(0,0,c.width,c.height); if(onClear)onClear(); };
  const save=()=>{ if(onSave)onSave(ref.current.toDataURL()); };
  useEffect(()=>{
    const el=ref.current; if(!el)return;
    el.addEventListener("mousedown",start); el.addEventListener("mousemove",move);
    el.addEventListener("mouseup",end); el.addEventListener("mouseleave",end);
    el.addEventListener("touchstart",start,{passive:false}); el.addEventListener("touchmove",move,{passive:false});
    el.addEventListener("touchend",end);
    return()=>{ el.removeEventListener("mousedown",start); el.removeEventListener("mousemove",move); el.removeEventListener("mouseup",end); el.removeEventListener("mouseleave",end); el.removeEventListener("touchstart",start); el.removeEventListener("touchmove",move); el.removeEventListener("touchend",end); };
  },[]);
  return(
    <div style={{display:"flex",flexDirection:"column",gap:10}}>
      <div style={{fontSize:12,color:"#3a6090",fontWeight:600,letterSpacing:.5,textTransform:"uppercase"}}>{label||"Signature"}</div>
      <div style={{border:"1px solid #d8e2f0",borderRadius:10,overflow:"hidden",background:"#f8fafc"}}>
        <canvas ref={ref} width={460} height={130} style={{display:"block",cursor:"crosshair",width:"100%"}}/>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={clear} style={{flex:1,padding:"8px",background:"#f5f8ff",border:"1px solid #dde4f0",borderRadius:8,color:"#3a5a8a",fontSize:12,cursor:"pointer",fontFamily:"'Plus Jakarta Sans',sans-serif"}}>Clear</button>
        <button onClick={save} style={{flex:2,padding:"8px",background:"linear-gradient(135deg,#1d6ef5,#2563eb)",border:"none",borderRadius:8,color:"#fff",fontSize:12,cursor:"pointer",fontWeight:600,fontFamily:"'Plus Jakarta Sans',sans-serif"}}>Confirm Signature</button>
      </div>
    </div>
  );
}


/* ─── REAL IMAGE BACKGROUNDS ───────────────────────────────── */
function SceneBackground({page}){
  const key = page==="project-detail"?"projects":page==="problems"?"problems":page==="admin"?"dashboard":page||"dashboard";
  const img = BG_IMAGES[key]||BG_IMAGES.dashboard;

  // Minimal per-page tint — just enough to ground the UI, image dominates
  const tints = {
    login:     "rgba(3,5,12,.62)",
    dashboard: "rgba(3,6,15,.22)",
    projects:  "rgba(4,3,8,.22)",
    problems:  "rgba(5,3,10,.22)",
    signin:    "rgba(2,6,4,.20)",
    reports:   "rgba(3,3,8,.20)",
    documents: "rgba(2,5,3,.20)",
  };
  const tint = tints[key]||"rgba(3,6,15,.22)";

  return(
    <>
      {/* Full-screen cinematic brewery photo */}
      <div style={{
        position:"fixed",inset:0,zIndex:0,
        backgroundImage:`url(${img})`,
        backgroundSize:"cover",
        backgroundPosition:"center center",
        backgroundRepeat:"no-repeat",
        transition:"background-image 0.8s ease",
        filter:"saturate(1.35) brightness(0.82) contrast(1.12)"
      }}/>
      {/* Minimal dark vignette — image stays vivid, edges slightly grounded */}
      <div style={{
        position:"fixed",inset:0,zIndex:1,
        background:`linear-gradient(180deg, ${tint} 0%, rgba(0,0,0,.08) 40%, rgba(0,0,0,.15) 100%)`,
        transition:"background 0.6s ease"
      }}/>
    </>
  );
}

/* ─── LOGIN VIEW ────────────────────────────────────────────── */
function Login({onLogin}){
  const [sel,setSel]=useState(null);
  const [pw,setPw]=useState(""); const [show,setShow]=useState(false);
  const [err,setErr]=useState("");
  const attempt=()=>{
    if(!sel){setErr("Please select your name.");return;}
    if(sel.password===pw){onLogin(sel);}
    else{setErr("Incorrect password. Please try again.");setPw("");}
  };
  return(
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",
      position:"relative",padding:24,overflow:"hidden"}}>
      <SceneBackground page="login"/>
      <div style={{position:"relative",zIndex:10,width:"100%",maxWidth:460}}>

        <div style={{textAlign:"center",marginBottom:40}}>
          <img src={`data:image/png;base64,${LOGO_B64}`} alt="TSOA" style={{height:56,marginBottom:20,filter:"drop-shadow(0 0 16px rgba(29,78,216,.25))"}}/>
          <div style={{fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:28,color:"#ffffff",letterSpacing:"-.5px",textShadow:"0 2px 20px rgba(0,0,0,.4)"}}>TSOA Technologies</div>
          <div style={{fontSize:13,color:"rgba(200,220,255,.85)",marginTop:4,fontFamily:"'Plus Jakarta Sans',sans-serif",letterSpacing:.5}}>Packaging Management System</div>
        </div>
        <Card className="scale-in" style={{padding:32,background:"#ffffff",border:"1px solid #e2e8f0",borderTop:"3px solid #1d4ed8",boxShadow:"0 8px 40px rgba(15,34,65,.18),0 2px 8px rgba(15,34,65,.08)"}}>
          <div style={{fontSize:12,color:"#3d5a8a",fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:14}}>Select Your Name</div>
          <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:24}}>
            {USERS.map(u=>(
              <button key={u.id} onClick={()=>{setSel(u);setErr("");setPw("");}}
                style={{display:"flex",alignItems:"center",gap:12,padding:"11px 14px",borderRadius:10,cursor:"pointer",
                  border:`1px solid ${sel?.id===u.id?"#1d4ed8":"#e2e8f0"}`,background:sel?.id===u.id?"#f0f7ff":"#ffffff",
                  background:sel?.id===u.id?"rgba(29,78,216,.08)":"#fafcff",transition:"all .15s"}}>
                <Avatar initials={u.avatar} size={36}/>
                <div style={{textAlign:"left"}}>
                  <div style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:600,fontSize:14,color:"#1e3a6e"}}>{u.name}</div>
                  <div style={{fontSize:11,color:"#3d5a8a"}}>{u.role}</div>
                </div>
                {sel?.id===u.id&&<div style={{marginLeft:"auto",color:"#3b82f6",display:"flex"}}><I n="check" s={18} c="#3b82f6"/></div>}
              </button>
            ))}
          </div>
          <div style={{fontSize:12,color:"#3d5a8a",fontWeight:700,letterSpacing:1,textTransform:"uppercase",marginBottom:10}}>Password</div>
          <div style={{position:"relative",marginBottom:16}}>
            <input
              type={show?"text":"password"}
              value={pw}
              onChange={e=>{setPw(e.target.value);setErr("");}}
              onKeyDown={e=>{if(e.key==="Enter")attempt();}}
              placeholder={sel?"Enter your password":"Select your name first"}
              disabled={!sel}
              style={{width:"100%",padding:"13px 46px 13px 16px",borderRadius:10,
                border:`1px solid ${err?"#ef444460":pw?"rgba(59,130,246,.4)":"rgba(59,130,246,.18)"}`,
                background:"#f8fafc",color:"#05122e",fontSize:14,
                fontFamily:"'Plus Jakarta Sans',sans-serif",transition:"border-color .2s",
                opacity:sel?1:.5}}/>
            <button onClick={()=>setShow(s=>!s)}
              style={{position:"absolute",right:14,top:"50%",transform:"translateY(-50%)",
                background:"none",border:"none",color:"#3d5a8a",fontSize:16,cursor:"pointer",padding:0,lineHeight:1}}>
              {show?<I n="eyeOff" s={16} c="#6080a8"/>:<I n="eye" s={16} c="#6080a8"/>}
            </button>
          </div>
          {err&&(
            <div style={{display:"flex",alignItems:"center",gap:7,padding:"9px 12px",marginBottom:14,
              background:"#fff5f5",border:"1px solid #fecaca",borderLeft:"3px solid #ef4444",borderRadius:8}}>
              <span style={{fontSize:14}}>⚠️</span>
              <span style={{color:"#ef4444",fontSize:12,fontFamily:"'Plus Jakarta Sans',sans-serif"}}>{err}</span>
            </div>
          )}
          <button onClick={attempt}
            style={{width:"100%",padding:"14px",background:"linear-gradient(135deg,#1d6ef5,#2563eb)",
              border:"none",borderRadius:10,color:"#fff",fontSize:14,fontWeight:700,cursor:"pointer",
              fontFamily:"'Plus Jakarta Sans',sans-serif",letterSpacing:.3,
              boxShadow:"0 4px 20px rgba(29,110,245,.35)",opacity:sel&&pw?1:.6,transition:"opacity .2s"}}>
            Sign In →
          </button>
          <div style={{fontSize:10,textAlign:"center",color:"#6b84a8",marginTop:14}}>
            Demo passwords: Tsoa@1234 · Tsoa@2345 · Tsoa@3456 · Admin@0000
          </div>
        </Card>
      </div>
    </div>
  );
}

